INSERT INTO Vrsta_Resursa (vrsta_resursa_id, naziv, opis) VALUES
                                                              (1, 'Učesnici eksperimenta', 'Ljudski učesnici podeljeni po iskustvu, profilu ili ulozi u eksperimentu.'),
                                                              (2, 'Virtuelni novac', 'Eksperimentalni novac koji se koristi za kupovinu, prodaju i isplate u simulaciji.'),
                                                              (3, 'Tokeni', 'Diskretne jedinice za glasanje, ulaganje, licitiranje ili raspodelu resursa.'),
                                                              (4, 'Početni kapital', 'Paketi početnog kapitala koji se dodeljuju učesnicima pre početka igre.'),
                                                              (5, 'Tržišni podaci', 'Skupovi podataka o cenama, potražnji, zalihama i transakcijama.'),
                                                              (6, 'Simulirana roba', 'Roba kojom se trguje u eksperimentalnom tržištu.'),
                                                              (7, 'Kuponi', 'Kuponi za popuste, podsticaje ili ograničene pogodnosti unutar simulacije.'),
                                                              (8, 'Nagrade', 'Novčane i nenovčane nagrade za učesnike prema rezultatima eksperimenta.'),
                                                              (9, 'Informacioni paketi', 'Različiti skupovi informacija koji se daju učesnicima radi testiranja asimetrije informacija.'),
                                                              (10, 'Evidencioni materijal', 'Obrasci, saglasnosti, instrukcije i zapisnici potrebni za sprovođenje sesije.');
