INSERT INTO Istrazivac (istrazivac_id, ime, prezime, email, institucija, kvalifikacije, sposobnosti) VALUES
                                                                                                         (1, 'Teodora', 'Ristić', 'teodora.ristic1@econlab.rs', 'Institut za ekonomska istraživanja', 'master ekonomije, fokus na aukcije, tržišnu ravnotežu i empirijsku analizu', 'statističko testiranje, regresiona analiza, obrada anketa i analiza rizika'),
                                                                                                         (2, 'Filip', 'Lazarević', 'filip.lazarevic2@econlab.rs', 'Fakultet organizacionih nauka', 'istraživač saradnik, iskustvo u laboratorijskim igrama i obradi panel podataka', 'rad sa oTree/z-Tree platformama, anonimna komunikacija i obračun isplata'),
                                                                                                         (3, 'Nina', 'Savić', 'nina.savic3@econlab.rs', 'Privatni istraživački centar za tržišne simulacije', 'asistent na predmetima mikroekonomija i bihejvioralna ekonomija', 'vođenje sesija, davanje instrukcija, kontrola toka rundi i izvoz rezultata'),
                                                                                                         (4, 'Ognjen', 'Obradović', 'ognjen.obradovic4@econlab.rs', 'Univerzitet u Novom Sadu - laboratorija za eksperimentalnu ekonomiju', 'data analitičar, specijalizovan za eksperimentalne podatke i vizuelizaciju rezultata', 'modelovanje tržišta, simulacija ponude i tražnje, priprema instrukcija'),
