                                                         (1, 'RSD', 'Srpski dinar', 'дин'),
                                                         (2, 'EUR', 'Evro', '€'),
                                                         (3, 'USD', 'Američki dolar', '$'),
                                                         (4, 'GBP', 'Britanska funta', '£'),
                                                         (5, 'CHF', 'Švajcarski franak', 'CHF'),
                                                         (6, 'EXP', 'Eksperimentalna valuta', 'EX'),
                                                         (7, 'TOK', 'Tržišni token', 'T'),
                                                         (8, 'ECU', 'Eksperimentalna kreditna jedinica', 'ECU'),
