INSERT INTO Eksperiment (eksperiment_id, naziv, opis, cilj_istrazivanja, predvidjeni_broj_ucesnika, budzet, valuta_budzeta_id, pravila, trzisni_uslovi, nacin_merenja_rezultata) VALUES
                                                                                                                                                                                     (1, 'Dvostruka aukcija na tržište reklamnog prostora u uslovima visokih transakcionih troškova', 'Eksperiment ispituje kako se učesnici ponašaju kada se kupci i prodavci istovremeno šalju ponude i tražnje na simuliranom tržištu.', 'Procena uticaja pravila ''dvostruka aukcija'' na cene, profit, efikasnost i percepciju pravičnosti.', 32, 93750.0, 1, 'Učesnici dobijaju početne instrukcije, nasumično se raspoređuju po ulogama i učestvuju u više rundi. Osnovni mehanizam je: kupci i prodavci istovremeno šalju ponude i tražnje. Zabranjena je komunikacija van dozvoljenih kanala.', 'Simulacija se odnosi na tržište reklamnog prostora; tretman uključuje u uslovima visokih transakcionih troškova, kontrolisane informacije i ograničen budžet učesnika.', 'Mere se prosečna cena, broj uspešnih transakcija, profit učesnika, tržišna efikasnost, raspodela isplata i odgovori iz ankete posle sesije.'),
                                                                                                                                                                                     (2, 'Aukcija druge cene na tržište studentskih udžbenika uz mogućnost anonimne komunikacije', 'Eksperiment ispituje kako se učesnici ponašaju kada se pobednik plaća drugu najvišu ponudu, uz privatne vrednosti na simuliranom tržištu.', 'Procena uticaja pravila ''aukcija druge cene'' na cene, profit, efikasnost i percepciju pravičnosti.', 40, 107500.0, 1, 'Učesnici dobijaju početne instrukcije, nasumično se raspoređuju po ulogama i učestvuju u više rundi. Osnovni mehanizam je: pobednik plaća drugu najvišu ponudu, uz privatne vrednosti. Zabranjena je komunikacija van dozvoljenih kanala.', 'Simulacija se odnosi na tržište studentskih udžbenika; tretman uključuje uz mogućnost anonimne komunikacije, kontrolisane informacije i ograničen budžet učesnika.', 'Mere se prosečna cena, broj uspešnih transakcija, profit učesnika, tržišna efikasnost, raspodela isplata i odgovori iz ankete posle sesije.'),
