DELETE FROM Status_Resursa_Laboratorije;
DELETE FROM Resurs;
DELETE FROM Jedinica_Mere;
DELETE FROM Vrsta_Resursa;
DELETE FROM Laboratorija;
DELETE FROM Tip_Laboratorije;

SET FOREIGN_KEY_CHECKS = 1;


