-- ============================================================
-- Brze provere posle izvrsavanja
-- ============================================================

SELECT 'Eksperimenti bez 2-6 sesija' AS provera, COUNT(*) AS broj
FROM (
         SELECT e.eksperiment_id, COUNT(s.sesija_id) AS broj_sesija
         FROM Eksperiment e
                  JOIN Izvodjenje i ON i.eksperiment_id = e.eksperiment_id
                  JOIN Sesija s ON s.izvodjenje_id = i.izvodjenje_id
         GROUP BY e.eksperiment_id
         HAVING COUNT(s.sesija_id) < 2 OR COUNT(s.sesija_id) > 6
     ) x;

SELECT 'Ukupan broj eksperimenata' AS provera, COUNT(*) AS broj FROM Eksperiment;
SELECT 'Ukupan broj sesija' AS provera, COUNT(*) AS broj FROM Sesija;
SELECT 'Ukupan broj istrazivaca' AS provera, COUNT(*) AS broj FROM Istrazivac;
